'use client';

const COMMAND_CENTER_HTML = "<!DOCTYPE html>\n<html lang=\"de\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<meta name=\"apple-mobile-web-app-capable\" content=\"yes\">\n<meta name=\"apple-mobile-web-app-title\" content=\"ARGONAUT\">\n<title>ARGONAUT COMMAND CENTER</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Orbitron:wght@400;700;900&family=Exo+2:wght@300;400;600;700&display=swap\" rel=\"stylesheet\">\n<style>\n:root{\n  --cyan:#00e5ff;--cyan-dim:#00b8d4;--cyan-dark:#004d61;\n  --gold:#C9A84C;--gold-dim:#7a5f1e;--gold-bright:#f0c060;\n  --navy:#020c1b;--navy-panel:#060f1e;--navy-sidebar:#030b16;\n  --text:#c8e8f4;--text-dim:#3d6b7a;--text-bright:#e8f8ff;\n  --border:rgba(0,229,255,0.1);--border-b:rgba(0,229,255,0.28);\n  --green:#00e676;--red:#ff5252;\n  --sw:200px;\n}\n*{margin:0;padding:0;box-sizing:border-box;}\nhtml,body{width:100%;height:100%;background:var(--navy);color:var(--text);font-family:'Exo 2',sans-serif;overflow:hidden;}\nbody::before{content:'';position:fixed;inset:0;z-index:997;pointer-events:none;background:repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,0,0,0.025) 3px,rgba(0,0,0,0.025) 4px);}\n.bg-grid{position:fixed;inset:0;z-index:0;pointer-events:none;background-image:linear-gradient(rgba(0,229,255,0.022) 1px,transparent 1px),linear-gradient(90deg,rgba(0,229,255,0.022) 1px,transparent 1px);background-size:50px 50px;}\n\n/* \u2550\u2550\u2550 BOOT \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n#boot{position:fixed;inset:0;z-index:600;background:var(--navy);display:flex;flex-direction:column;align-items:center;justify-content:center;gap:2.5rem;}\n.boot-logo{font-family:'Orbitron',monospace;font-size:clamp(3rem,9vw,7rem);font-weight:900;letter-spacing:.4em;color:var(--cyan);text-shadow:0 0 50px rgba(0,229,255,.95),0 0 100px rgba(0,229,255,.4);overflow:hidden;border-right:4px solid var(--cyan);white-space:nowrap;width:0;animation:typing 2.4s steps(8,end) .6s forwards,blink .7s step-end 3.1s 4;}\n@keyframes typing{from{width:0}to{width:12ch}}\n@keyframes blink{50%{border-color:transparent}}\n.boot-tag{font-family:'Share Tech Mono',monospace;font-size:.9rem;color:var(--text-dim);letter-spacing:.3em;opacity:0;animation:fi .5s ease 2.9s forwards;}\n.boot-lines{font-family:'Share Tech Mono',monospace;font-size:.82rem;color:var(--cyan-dim);width:460px;max-width:90vw;}\n.bl{opacity:0;margin:5px 0;}\n.bl:nth-child(1){animation:fi .3s ease 3.2s forwards;}\n.bl:nth-child(2){animation:fi .3s ease 3.5s forwards;}\n.bl:nth-child(3){animation:fi .3s ease 3.8s forwards;}\n.bl:nth-child(4){animation:fi .3s ease 4.1s forwards;}\n.bl:nth-child(5){animation:fi .3s ease 4.4s forwards;}\n.ok{color:var(--gold);}\n.boot-bar-w{width:460px;max-width:90vw;opacity:0;animation:fi .4s ease 4.7s forwards;}\n.boot-bar-l{font-family:'Share Tech Mono',monospace;font-size:.68rem;color:var(--text-dim);letter-spacing:.15em;margin-bottom:7px;}\n.boot-bar{height:2px;background:rgba(0,229,255,.07);overflow:hidden;}\n.boot-bar-f{height:100%;width:0;background:linear-gradient(90deg,var(--cyan-dark),var(--cyan));box-shadow:0 0 10px var(--cyan);animation:bf 1.4s ease 4.9s forwards;}\n@keyframes bf{to{width:100%}}\n@keyframes fi{to{opacity:1}}\n\n/* \u2550\u2550\u2550 APP SHELL \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n#app{position:fixed;inset:0;z-index:100;display:none;flex-direction:column;}\n\n/* TOPBAR */\n.topbar{height:56px;flex-shrink:0;background:rgba(2,8,20,.98);border-bottom:1px solid var(--border-b);display:flex;align-items:center;padding:0 1.2rem;gap:1.2rem;z-index:20;}\n.logo-b{display:flex;flex-direction:column;padding-right:1.2rem;border-right:1px solid var(--border);flex-shrink:0;}\n.logo-w{font-family:'Orbitron',monospace;font-weight:900;font-size:1.05rem;letter-spacing:.32em;color:var(--cyan);text-shadow:0 0 12px rgba(0,229,255,.6);}\n.logo-s{font-family:'Share Tech Mono',monospace;font-size:.55rem;letter-spacing:.18em;color:var(--text-dim);}\n.tabs{display:flex;gap:1px;flex:1;}\n.tab{font-family:'Share Tech Mono',monospace;font-size:.72rem;letter-spacing:.13em;padding:8px 14px;border:none;background:transparent;color:var(--text-dim);cursor:pointer;border-bottom:2px solid transparent;transition:all .2s;white-space:nowrap;}\n.tab:hover{color:var(--text);}\n.tab.active{color:var(--cyan);border-bottom-color:var(--cyan);text-shadow:0 0 8px rgba(0,229,255,.5);}\n.tb-r{display:flex;align-items:center;gap:1.2rem;flex-shrink:0;}\n.live-dot{display:flex;align-items:center;gap:5px;font-family:'Share Tech Mono',monospace;font-size:.72rem;color:var(--text-dim);}\n.live-dot::before{content:'';width:7px;height:7px;border-radius:50%;background:var(--cyan);box-shadow:0 0 7px var(--cyan);animation:pu 2s ease-in-out infinite;}\n@keyframes pu{0%,100%{opacity:1}50%{opacity:.3}}\n.clk{font-family:'Share Tech Mono',monospace;font-size:.95rem;color:var(--gold);letter-spacing:.08em;}\n.rbtn{background:none;border:1px solid var(--border);color:var(--text-dim);cursor:pointer;font-family:'Share Tech Mono',monospace;font-size:.68rem;letter-spacing:.1em;padding:5px 11px;transition:all .2s;}\n.rbtn:hover{border-color:var(--cyan);color:var(--cyan);}\n\n/* BODY */\n.body{flex:1;display:flex;overflow:hidden;}\n\n/* SIDEBAR */\n.sb{width:var(--sw);flex-shrink:0;background:var(--navy-sidebar);border-right:1px solid var(--border);display:flex;flex-direction:column;overflow:hidden;}\n.sb-user{display:flex;align-items:center;gap:.7rem;padding:.9rem 1rem;border-bottom:1px solid var(--border);}\n.av{width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,var(--cyan-dark),var(--cyan));display:flex;align-items:center;justify-content:center;font-family:'Orbitron',monospace;font-size:.75rem;font-weight:900;color:#000;flex-shrink:0;}\n.un{font-size:.82rem;font-weight:700;color:var(--text-bright);}\n.ur{font-family:'Share Tech Mono',monospace;font-size:.58rem;color:var(--text-dim);letter-spacing:.08em;}\n.sb-sec{padding:.65rem 1rem .2rem;font-family:'Share Tech Mono',monospace;font-size:.52rem;letter-spacing:.2em;color:var(--text-dim);}\n.sb-nav{flex:1;overflow-y:auto;padding:.2rem 0;scrollbar-width:none;}\n.ni{display:flex;align-items:center;gap:.65rem;padding:.65rem 1rem;cursor:pointer;transition:all .2s;border-left:2px solid transparent;}\n.ni:hover{background:rgba(0,229,255,.04);color:var(--text-bright);}\n.ni.active{background:rgba(0,229,255,.06);border-left-color:var(--cyan);color:var(--cyan);}\n.ni-ic{font-size:.95rem;width:18px;text-align:center;flex-shrink:0;}\n.ni-lb{font-size:.8rem;font-weight:600;}\n.ni-bd{margin-left:auto;font-family:'Share Tech Mono',monospace;font-size:.58rem;padding:1px 5px;background:rgba(0,229,255,.12);color:var(--cyan);}\n.sb-bot{border-top:1px solid var(--border);padding:.8rem 1rem;}\n.sh-row{display:flex;align-items:center;justify-content:space-between;margin-bottom:.4rem;}\n.sh-l{font-family:'Share Tech Mono',monospace;font-size:.62rem;color:var(--text-dim);}\n.sh-v{font-family:'Orbitron',monospace;font-size:.82rem;color:var(--green);}\n.sh-bar{height:3px;background:rgba(0,229,255,.08);border-radius:2px;overflow:hidden;}\n.sh-f{height:100%;width:98.7%;background:linear-gradient(90deg,var(--cyan-dark),var(--green));box-shadow:0 0 6px var(--green);}\n\n/* MAIN */\n.main{flex:1;display:flex;flex-direction:column;overflow:hidden;}\n.panel-wrap{flex:1;overflow:hidden;display:flex;flex-direction:column;}\n.tp{display:none;flex:1;overflow-y:auto;padding:1.2rem 1.4rem;flex-direction:column;gap:1.1rem;scrollbar-width:thin;scrollbar-color:var(--cyan-dark) var(--navy);}\n.tp.active{display:flex;}\n\n/* METRICS */\n.mets{display:grid;grid-template-columns:repeat(4,1fr);gap:.9rem;}\n.mc{background:var(--navy-panel);border:1px solid var(--border);border-top:2px solid var(--cyan-dark);padding:1rem 1.2rem;position:relative;overflow:hidden;transition:border-color .25s;}\n.mc:hover{border-color:var(--border-b);border-top-color:var(--cyan);}\n.mc::before{content:'';position:absolute;top:0;left:0;right:0;height:1px;background:linear-gradient(90deg,transparent,rgba(0,229,255,.35),transparent);}\n.mc-l{font-family:'Share Tech Mono',monospace;font-size:.68rem;letter-spacing:.15em;color:var(--text-dim);text-transform:uppercase;margin-bottom:.4rem;}\n.mc-v{font-family:'Orbitron',monospace;font-size:1.85rem;font-weight:700;color:var(--cyan);text-shadow:0 0 10px rgba(0,229,255,.28);line-height:1;}\n.mc-v.g{color:var(--gold);text-shadow:0 0 10px rgba(201,168,76,.28);}\n.mc-v.gr{color:var(--green);}\n.mc-s{font-family:'Share Tech Mono',monospace;font-size:.66rem;color:var(--text-dim);margin-top:.38rem;}\n.mc-s.up{color:var(--green);}\n.co{position:absolute;width:9px;height:9px;border-color:rgba(0,229,255,.4);border-style:solid;}\n.ctl{top:0;left:0;border-width:2px 0 0 2px;}\n.cbr{bottom:0;right:0;border-width:0 2px 2px 0;}\n\n/* PANEL */\n.pn{background:var(--navy-panel);border:1px solid var(--border);overflow:hidden;}\n.pnh{display:flex;align-items:center;justify-content:space-between;padding:.75rem 1.1rem;border-bottom:1px solid var(--border);background:rgba(0,229,255,.018);}\n.pnt{font-family:'Orbitron',monospace;font-size:.68rem;font-weight:700;letter-spacing:.18em;color:var(--cyan);}\n.pnb{font-family:'Share Tech Mono',monospace;font-size:.62rem;letter-spacing:.08em;color:var(--text-dim);border:1px solid var(--border);padding:2px 8px;}\n.pnbody{padding:.85rem 1.1rem;}\n\n/* RADAR CENTER */\n.radar-section{display:grid;grid-template-columns:1fr 280px 1fr;gap:1rem;align-items:start;}\n.radar-wrap{display:flex;align-items:center;justify-content:center;padding:.5rem;}\n.radar{position:relative;width:260px;height:260px;}\n.radar canvas{position:absolute;top:0;left:0;}\n.radar-center{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);display:flex;flex-direction:column;align-items:center;justify-content:center;z-index:10;}\n.radar-a{font-family:'Orbitron',monospace;font-size:2.8rem;font-weight:900;color:var(--gold);text-shadow:0 0 30px rgba(201,168,76,.9),0 0 60px rgba(201,168,76,.4);line-height:1;}\n.radar-sub{font-family:'Share Tech Mono',monospace;font-size:.55rem;letter-spacing:.2em;color:var(--text-dim);margin-top:.2rem;}\n.radar-active{font-family:'Orbitron',monospace;font-size:.9rem;color:var(--cyan);text-shadow:0 0 8px rgba(0,229,255,.6);}\n\n/* TABLE */\n.tbl{width:100%;border-collapse:collapse;}\n.tbl th{font-family:'Share Tech Mono',monospace;font-size:.62rem;letter-spacing:.12em;color:var(--text-dim);text-align:left;padding:.4rem .5rem;border-bottom:1px solid var(--border);text-transform:uppercase;}\n.tbl td{font-size:.82rem;padding:.5rem .5rem;border-bottom:1px solid rgba(0,229,255,.04);font-family:'Share Tech Mono',monospace;color:var(--text);}\n.tbl tr:last-child td{border-bottom:none;}\n.tbl tr:hover td{background:rgba(0,229,255,.025);}\n.pk{font-size:.62rem;padding:2px 7px;border:1px solid;letter-spacing:.06em;}\n.pk-s{color:var(--gold);border-color:var(--gold-dim);}\n.pk-st{color:var(--cyan);border-color:var(--cyan-dark);}\n.pk-p{color:#e040fb;border-color:#7b1fa2;}\n.pk-b{color:#76ff03;border-color:#4caf50;}\n.pk-e{color:#ff9100;border-color:#e65100;}\n.sa{color:var(--green);font-size:.72rem;}\n\n/* PAYMENTS */\n.pi{display:flex;align-items:center;justify-content:space-between;padding:.5rem 0;border-bottom:1px solid rgba(0,229,255,.04);}\n.pi:last-child{border-bottom:none;}\n.pil{display:flex;flex-direction:column;gap:2px;}\n.pin{font-size:.82rem;color:var(--text);}\n.pid{font-family:'Share Tech Mono',monospace;font-size:.65rem;color:var(--text-dim);}\n.pia{font-family:'Orbitron',monospace;font-size:.9rem;font-weight:700;color:var(--gold);}\n\n/* AGENT GRID */\n.ag-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:.5rem;}\n.ag-card{background:rgba(0,229,255,.02);border:1px solid var(--border);padding:.7rem .85rem;display:flex;align-items:center;gap:.55rem;transition:all .2s;}\n.ag-card:hover{border-color:var(--border-b);background:rgba(0,229,255,.05);}\n.ag-dot{width:8px;height:8px;border-radius:50%;flex-shrink:0;}\n.a-on{background:var(--cyan);box-shadow:0 0 6px var(--cyan);}\n.a-id{font-family:'Orbitron',monospace;font-size:.65rem;font-weight:700;color:var(--cyan);}\n.a-nm{font-family:'Share Tech Mono',monospace;font-size:.68rem;color:var(--text-dim);}\n.a-sr{font-family:'Share Tech Mono',monospace;font-size:.55rem;color:var(--text-dim);margin-left:auto;}\n\n/* BARS */\n.bars{display:flex;align-items:flex-end;gap:5px;height:100px;}\n.bc{display:flex;flex-direction:column;align-items:center;gap:3px;flex:1;}\n.bar{width:100%;background:linear-gradient(180deg,var(--cyan),var(--cyan-dark));border-top:1px solid var(--cyan);min-height:2px;}\n.bar.gb{background:linear-gradient(180deg,var(--gold),var(--gold-dim));border-top-color:var(--gold);}\n.bl2{font-family:'Share Tech Mono',monospace;font-size:.52rem;color:var(--text-dim);}\n.tfb{font-family:'Share Tech Mono',monospace;font-size:.68rem;letter-spacing:.08em;padding:4px 10px;border:1px solid var(--border);background:transparent;color:var(--text-dim);cursor:pointer;transition:all .2s;}\n.tfb:hover{border-color:var(--cyan-dim);color:var(--text);}\n.tfb.active{border-color:var(--cyan);color:var(--cyan);background:rgba(0,229,255,.05);}\n\n/* FORECAST */\n.fc-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:.75rem;}\n.fc-c{background:rgba(201,168,76,.03);border:1px solid rgba(201,168,76,.18);padding:.9rem;text-align:center;}\n.fc-h{font-family:'Share Tech Mono',monospace;font-size:.65rem;color:var(--text-dim);letter-spacing:.12em;margin-bottom:.4rem;}\n.fc-v{font-family:'Orbitron',monospace;font-size:1.3rem;font-weight:700;color:var(--gold);}\n.fc-s{font-family:'Share Tech Mono',monospace;font-size:.6rem;color:var(--text-dim);margin-top:.3rem;}\n\n/* WF */\n.wfi{display:flex;align-items:center;justify-content:space-between;padding:.5rem 0;border-bottom:1px solid rgba(0,229,255,.04);}\n.wfi:last-child{border-bottom:none;}\n.wfn{font-family:'Share Tech Mono',monospace;font-size:.78rem;color:var(--text);}\n.wf-on{font-size:.62rem;padding:2px 8px;color:var(--green);border:1px solid rgba(0,230,118,.22);}\n.wf-off{font-size:.62rem;padding:2px 8px;color:var(--gold);border:1px solid rgba(201,168,76,.22);}\n\n/* LOG */\n.li{display:flex;gap:.7rem;padding:.5rem 0;border-bottom:1px solid rgba(0,229,255,.04);}\n.li:last-child{border-bottom:none;}\n.lt{font-family:'Share Tech Mono',monospace;font-size:.65rem;color:var(--text-dim);white-space:nowrap;flex-shrink:0;}\n.ld{width:6px;height:6px;border-radius:50%;flex-shrink:0;margin-top:4px;}\n.ltx{font-family:'Share Tech Mono',monospace;font-size:.75rem;color:var(--text);line-height:1.45;}\n\n/* SYS */\n.syi{display:flex;align-items:center;justify-content:space-between;padding:.55rem 0;border-bottom:1px solid rgba(0,229,255,.04);}\n.syi:last-child{border-bottom:none;}\n.syn{font-family:'Share Tech Mono',monospace;font-size:.78rem;color:var(--text);}\n.sy-ok{font-family:'Share Tech Mono',monospace;font-size:.68rem;color:var(--green);display:flex;align-items:center;gap:5px;}\n.sy-ok::before{content:'';width:6px;height:6px;border-radius:50%;background:var(--green);box-shadow:0 0 5px var(--green);}\n\n/* CHAT */\n.chat-wrap{display:flex;flex-direction:column;height:220px;}\n.chat-msgs{flex:1;overflow-y:auto;padding:.6rem 0;display:flex;flex-direction:column;gap:.5rem;scrollbar-width:thin;scrollbar-color:var(--cyan-dark) var(--navy);}\n.msg{display:flex;gap:.6rem;align-items:flex-start;}\n.msg.user{flex-direction:row-reverse;}\n.msg-av{width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-family:'Orbitron',monospace;font-size:.6rem;font-weight:700;flex-shrink:0;}\n.msg-av.ai{background:linear-gradient(135deg,var(--cyan-dark),var(--cyan));color:#000;}\n.msg-av.u{background:linear-gradient(135deg,var(--gold-dim),var(--gold));color:#000;}\n.msg-txt{background:rgba(0,229,255,.06);border:1px solid var(--border);padding:.5rem .75rem;font-size:.78rem;line-height:1.45;color:var(--text);max-width:85%;}\n.msg.user .msg-txt{background:rgba(201,168,76,.07);border-color:rgba(201,168,76,.2);}\n.chat-inp{display:flex;gap:.5rem;margin-top:.6rem;border-top:1px solid var(--border);padding-top:.6rem;}\n.chat-input{flex:1;background:rgba(0,229,255,.04);border:1px solid var(--border);color:var(--text);font-family:'Exo 2',sans-serif;font-size:.82rem;padding:.5rem .75rem;outline:none;transition:border-color .2s;}\n.chat-input:focus{border-color:var(--cyan-dim);}\n.chat-send{background:linear-gradient(135deg,var(--cyan-dark),var(--cyan));border:none;color:#000;font-family:'Orbitron',monospace;font-size:.65rem;font-weight:700;letter-spacing:.1em;padding:.5rem 1rem;cursor:pointer;}\n\n/* PIPELINE */\n.deal{display:flex;align-items:center;justify-content:space-between;padding:.6rem 0;border-bottom:1px solid rgba(0,229,255,.04);}\n.deal:last-child{border-bottom:none;}\n.deal-l{display:flex;flex-direction:column;gap:2px;}\n.deal-n{font-size:.85rem;font-weight:600;color:var(--text-bright);}\n.deal-s{font-family:'Share Tech Mono',monospace;font-size:.62rem;color:var(--text-dim);}\n.deal-r{display:flex;flex-direction:column;align-items:flex-end;gap:4px;}\n.deal-v{font-family:'Orbitron',monospace;font-size:.85rem;font-weight:700;color:var(--gold);}\n.deal-bar-w{width:80px;height:3px;background:rgba(0,229,255,.1);border-radius:2px;overflow:hidden;}\n.deal-bar-f{height:100%;background:linear-gradient(90deg,var(--cyan-dark),var(--cyan));border-radius:2px;}\n\n/* LAYOUT */\n.two-c{display:grid;grid-template-columns:1.35fr 1fr;gap:1rem;}\n.three-c{display:grid;grid-template-columns:1fr 1fr 1fr;gap:1rem;}\n.two-c-eq{display:grid;grid-template-columns:1fr 1fr;gap:1rem;}\n.loading{font-family:'Share Tech Mono',monospace;font-size:.75rem;color:var(--text-dim);animation:blink2 1s step-end infinite;}\n@keyframes blink2{50%{opacity:.2}}\n\n/* FOOTER */\n.footer{height:28px;flex-shrink:0;border-top:1px solid var(--border);background:rgba(2,8,20,.98);display:flex;align-items:center;justify-content:space-between;padding:0 1.3rem;}\n.ft{font-family:'Share Tech Mono',monospace;font-size:.58rem;letter-spacing:.1em;color:var(--text-dim);}\n.ft span{color:var(--cyan);}\n\n@media(max-width:1100px){\n  :root{--sw:0px;}\n  .sb{display:none;}\n  .mets{grid-template-columns:repeat(2,1fr);}\n  .radar-section{grid-template-columns:1fr;}\n  .two-c,.three-c,.two-c-eq{grid-template-columns:1fr;}\n  .ag-grid{grid-template-columns:repeat(2,1fr);}\n  html,body{overflow:auto;}\n  .tp{overflow:visible;}\n}\n@media(max-width:700px){\n  .tabs{overflow-x:auto;scrollbar-width:none;}\n  .tab{font-size:.65rem;padding:6px 10px;}\n  .mets{grid-template-columns:1fr 1fr;}\n  .fc-grid{grid-template-columns:1fr 1fr;}\n}\n/* Q8-POLITUR 15.07.26 */html{font-size:clamp(18px,1.35vw,22px)}:root{--text-dim:#7aa3b3}</style>\n</head>\n<body>\n<div class=\"bg-grid\"></div>\n\n<!-- BOOT -->\n<div id=\"boot\">\n  <div style=\"text-align:center;\">\n    <div class=\"boot-logo\">ARGONAUT</div>\n    <div class=\"boot-tag\" style=\"margin-top:.6rem;\">COMMAND CENTER v3.0 \u2014 B\u00d6BLINGEN NODE</div>\n  </div>\n  <div class=\"boot-lines\">\n    <div class=\"bl\">\u25b8 Systemkern wird initialisiert... <span class=\"ok\">OK</span></div>\n    <div class=\"bl\">\u25b8 Radar-Matrix wird kalibriert... <span class=\"ok\">OK</span></div>\n    <div class=\"bl\">\u25b8 Supabase Datenbankverbindung... <span class=\"ok\">OK</span></div>\n    <div class=\"bl\">\u25b8 24 Agenten werden synchronisiert... <span class=\"ok\">OK</span></div>\n    <div class=\"bl\">\u25b8 ARGONAUT COMMAND CENTER v3.0 bereit. <span class=\"ok\">ONLINE</span></div>\n  </div>\n  <div class=\"boot-bar-w\">\n    <div class=\"boot-bar-l\">SYSTEM START</div>\n    <div class=\"boot-bar\"><div class=\"boot-bar-f\"></div></div>\n  </div>\n</div>\n\n<!-- APP -->\n<div id=\"app\">\n\n  <!-- TOPBAR -->\n  <div class=\"topbar\">\n    <div class=\"logo-b\">\n      <div class=\"logo-w\">ARGONAUT</div>\n      <div class=\"logo-s\">COMMAND CENTER</div>\n    </div>\n    <div class=\"tabs\">\n      <button class=\"tab active\" onclick=\"showTab('overview',this)\">OVERVIEW</button>\n      <button class=\"tab\" onclick=\"showTab('analytics',this)\">ANALYTICS</button>\n      <button class=\"tab\" onclick=\"showTab('pipeline',this)\">PIPELINE</button>\n      <button class=\"tab\" onclick=\"showTab('agents',this)\">AGENTEN</button>\n      <button class=\"tab\" onclick=\"showTab('finanzen',this)\">FINANZEN</button>\n      <button class=\"tab\" onclick=\"showTab('systeme',this)\">SYSTEME</button>\n      <button class=\"tab\" onclick=\"showTab('logs',this)\">LOGS</button>\n      <button class=\"tab\" onclick=\"showTab('imperium',this)\" style=\"color:#C9A84C;\">\u2b22 IMPERIUM</button>\n    </div>\n    <div class=\"tb-r\">\n      <div class=\"live-dot\">LIVE</div>\n      <button class=\"rbtn\" onclick=\"loadData()\">\u21bb REFRESH</button>\n      <div class=\"clk\" id=\"clock\">00:00:00</div>\n    </div>\n  </div>\n\n  <!-- BODY -->\n  <div class=\"body\">\n\n    <!-- SIDEBAR -->\n    <div class=\"sb\">\n      <div class=\"sb-user\">\n        <div class=\"av\">MG</div>\n        <div>\n          <div class=\"un\">Martin Gaspar</div>\n          <div class=\"ur\">ADMINISTRATOR</div>\n        </div>\n      </div>\n      <div class=\"sb-sec\">HAUPTMEN\u00dc</div>\n      <div class=\"sb-nav\">\n        <div class=\"ni active\" onclick=\"showTab('overview',document.querySelector('.tab'))\"><span class=\"ni-ic\">\u2b21</span><span class=\"ni-lb\">Dashboard</span></div>\n        <div class=\"ni\" onclick=\"showTab('pipeline',document.querySelectorAll('.tab')[2])\"><span class=\"ni-ic\">\u25c8</span><span class=\"ni-lb\">Pipeline</span><span class=\"ni-bd\" id=\"sb-deals\">0</span></div>\n        <div class=\"ni\" onclick=\"showTab('finanzen',document.querySelectorAll('.tab')[4])\"><span class=\"ni-ic\">\u20ac</span><span class=\"ni-lb\">Finanzen</span></div>\n        <div class=\"ni\" onclick=\"showTab('analytics',document.querySelectorAll('.tab')[1])\"><span class=\"ni-ic\">\u25b2</span><span class=\"ni-lb\">Analytics</span></div>\n        <div class=\"sb-sec\">KI-SYSTEM</div>\n        <div class=\"ni\" onclick=\"showTab('agents',document.querySelectorAll('.tab')[3])\"><span class=\"ni-ic\">\u25c9</span><span class=\"ni-lb\">KI-Agenten</span><span class=\"ni-bd\">24</span></div>\n        <div class=\"ni\" onclick=\"showTab('systeme',document.querySelectorAll('.tab')[5])\"><span class=\"ni-ic\">\u2699</span><span class=\"ni-lb\">Systeme</span></div>\n        <div class=\"ni\" onclick=\"showTab('logs',document.querySelectorAll('.tab')[6])\"><span class=\"ni-ic\">\u25b8</span><span class=\"ni-lb\">Logs</span></div>\n        <div class=\"ni\" onclick=\"showTab('imperium',document.querySelectorAll('.tab')[7])\" style=\"border-top:1px solid #C9A84C33;margin-top:6px;padding-top:10px;\"><span class=\"ni-ic\" style=\"color:#C9A84C;\">\u2b22</span><span class=\"ni-lb\" style=\"color:#C9A84C;\">Imperium</span></div>\n      </div>\n      <div class=\"sb-bot\">\n        <div class=\"sh-row\">\n          <span class=\"sh-l\">SYSTEM HEALTH</span>\n          <span class=\"sh-v\">98.7%</span>\n        </div>\n        <div class=\"sh-bar\"><div class=\"sh-f\"></div></div>\n      </div>\n    </div>\n\n    <!-- MAIN -->\n    <div class=\"main\">\n      <div class=\"panel-wrap\">\n\n        <!-- \u2500\u2500 OVERVIEW \u2500\u2500 -->\n        <div class=\"tp active\" id=\"tab-overview\">\n          <div class=\"mets\">\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div>\n              <div class=\"mc-l\">MRR / Monat</div>\n              <div class=\"mc-v g\" id=\"mrr\">\u2014</div>\n              <div class=\"mc-s\" id=\"mrr-s\">Wird geladen...</div>\n            </div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div>\n              <div class=\"mc-l\">Aktive Kunden</div>\n              <div class=\"mc-v\" id=\"cust-n\">\u2014</div>\n              <div class=\"mc-s\" id=\"cust-s\">Wird geladen...</div>\n            </div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div>\n              <div class=\"mc-l\">Letzte Zahlung</div>\n              <div class=\"mc-v g\" id=\"last-pay\">\u2014</div>\n              <div class=\"mc-s\" id=\"last-pay-s\">\u2014</div>\n            </div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div>\n              <div class=\"mc-l\">Agenten Online</div>\n              <div class=\"mc-v gr\">24</div>\n              <div class=\"mc-s\">A/B/C/D/E Serie aktiv</div>\n            </div>\n          </div>\n\n          <!-- RADAR CENTER ROW -->\n          <div class=\"radar-section\">\n            <!-- LEFT: Kunden -->\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 Aktive Kunden</div><div class=\"pnb\" id=\"c-cnt\">LADE...</div></div>\n              <div class=\"pnbody\">\n                <table class=\"tbl\">\n                  <thead><tr><th>E-Mail</th><th>Paket</th><th>Status</th><th>Seit</th></tr></thead>\n                  <tbody id=\"cust-tbody\"><tr><td colspan=\"4\" class=\"loading\">\u25b8 Verbinde...</td></tr></tbody>\n                </table>\n              </div>\n            </div>\n\n            <!-- CENTER: RADAR -->\n            <div class=\"radar-wrap\">\n              <div class=\"radar\">\n                <canvas id=\"radarCanvas\" width=\"260\" height=\"260\"></canvas>\n                <div class=\"radar-center\">\n                  <div class=\"radar-a\">A</div>\n                  <div class=\"radar-sub\">COMMAND</div>\n                  <div class=\"radar-active\" id=\"radar-active-count\">24 ONLINE</div>\n                </div>\n              </div>\n            </div>\n\n            <!-- RIGHT: Zahlungen -->\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 Letzte Zahlungen</div><div class=\"pnb\">STRIPE LIVE</div></div>\n              <div class=\"pnbody\" id=\"pay-body\"><div class=\"loading\">\u25b8 Verbinde...</div></div>\n            </div>\n          </div>\n\n          <!-- CHAT + ACTIVITY -->\n          <div class=\"two-c-eq\">\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 KI-Assistent</div><div class=\"pnb\" style=\"color:var(--green);\">\u25cf ONLINE \u2014 MARTIN'S ZWILLING</div></div>\n              <div class=\"pnbody\">\n                <div class=\"chat-wrap\">\n                  <div class=\"chat-msgs\" id=\"chat-msgs\">\n                    <div class=\"msg\">\n                      <div class=\"msg-av ai\">A</div>\n                      <div class=\"msg-txt\">Guten Morgen, Martin! Dein Command Center ist online. Alle 24 Agenten aktiv. Wie kann ich dir heute helfen?</div>\n                    </div>\n                  </div>\n                  <div class=\"chat-inp\">\n                    <input class=\"chat-input\" id=\"chat-in\" placeholder=\"Schreib dem KI-Assistenten...\" onkeydown=\"if(event.key==='Enter')sendChat()\">\n                    <button class=\"chat-send\" onclick=\"sendChat()\">SENDEN</button>\n                  </div>\n                </div>\n              </div>\n            </div>\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 Aktivit\u00e4ts-Feed</div><div class=\"pnb\" id=\"feed-cnt\">0 EVENTS</div></div>\n              <div class=\"pnbody\" id=\"feed-body\"><div class=\"loading\">\u25b8 Lade Events...</div></div>\n            </div>\n          </div>\n        </div>\n\n        <!-- \u2500\u2500 ANALYTICS \u2500\u2500 -->\n        <div class=\"tp\" id=\"tab-analytics\">\n          <div class=\"mets\">\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">MRR aktuell</div><div class=\"mc-v g\" id=\"a-mrr\">\u2014</div><div class=\"mc-s\">Monatlich wiederkehrend</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Kunden gesamt</div><div class=\"mc-v\" id=\"a-tot\">\u2014</div><div class=\"mc-s\">Alle Pakete</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">\u00d8 Paket-Wert</div><div class=\"mc-v g\" id=\"a-avg\">\u2014</div><div class=\"mc-s\">Pro Kunde / Monat</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">ARR Hochrechnung</div><div class=\"mc-v\" id=\"a-arr\">\u2014</div><div class=\"mc-s\">MRR \u00d7 12</div></div>\n          </div>\n          <div class=\"pn\">\n            <div class=\"pnh\">\n              <div class=\"pnt\">\u25c8 Kunden-Wachstum</div>\n              <div style=\"display:flex;gap:4px;\">\n                <button class=\"tfb active\" onclick=\"setTF('1M',this)\">1M</button>\n                <button class=\"tfb\" onclick=\"setTF('3M',this)\">3M</button>\n                <button class=\"tfb\" onclick=\"setTF('6M',this)\">6M</button>\n                <button class=\"tfb\" onclick=\"setTF('12M',this)\">12M</button>\n              </div>\n            </div>\n            <div class=\"pnbody\">\n              <div style=\"font-family:'Share Tech Mono',monospace;font-size:.62rem;color:var(--text-dim);letter-spacing:.12em;margin-bottom:.6rem;\">KUNDEN PRO MONAT</div>\n              <div class=\"bars\" id=\"ch-bars\"><div class=\"loading\">\u25b8 Lade...</div></div>\n            </div>\n          </div>\n          <div class=\"pn\">\n            <div class=\"pnh\"><div class=\"pnt\">\u25c8 MRR-Entwicklung</div><div class=\"pnb\">\u20ac / MONAT</div></div>\n            <div class=\"pnbody\">\n              <div style=\"font-family:'Share Tech Mono',monospace;font-size:.62rem;color:var(--text-dim);letter-spacing:.12em;margin-bottom:.6rem;\">MONATLICH WIEDERKEHRENDER UMSATZ</div>\n              <div class=\"bars\" id=\"mrr-bars\"><div class=\"loading\">\u25b8 Lade...</div></div>\n            </div>\n          </div>\n          <div class=\"pn\">\n            <div class=\"pnh\"><div class=\"pnt\">\u25c8 Wachstums-Prognose</div><div class=\"pnb\">WENN SO WEITER</div></div>\n            <div class=\"pnbody\"><div class=\"fc-grid\" id=\"fc-grid\"><div class=\"loading\">\u25b8 Berechne...</div></div></div>\n          </div>\n        </div>\n\n        <!-- \u2500\u2500 PIPELINE \u2500\u2500 -->\n        <div class=\"tp\" id=\"tab-pipeline\">\n          <div class=\"mets\">\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Aktive Deals</div><div class=\"mc-v\" id=\"p-deals\">\u2014</div><div class=\"mc-s\">In Pipeline</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Pipeline Wert</div><div class=\"mc-v g\" id=\"p-val\">\u2014</div><div class=\"mc-s\">Gesamt offen</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">\u00d8 Abschluss</div><div class=\"mc-v gr\">\u2014</div><div class=\"mc-s\">Noch keine Daten</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Ziel Monat</div><div class=\"mc-v g\">16</div><div class=\"mc-s\">Kunden f\u00fcr Million\u00e4r</div></div>\n          </div>\n          <div class=\"two-c\">\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 Deal Pipeline</div><div class=\"pnb\">AKTIV</div></div>\n              <div class=\"pnbody\" id=\"pipeline-body\"><div style=\"color:var(--text-dim);font-size:.78rem;font-family:'Share Tech Mono',monospace;padding:.5rem 0;\">Noch keine Deals \u2014 Pipeline f\u00fcllt sich mit echten Leads.</div>\n              </div>\n            </div>\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 N\u00e4chste Schritte</div><div class=\"pnb\">HEUTE</div></div>\n              <div class=\"pnbody\">\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--red);\">\u25cf Holzente Sch\u00e4fer \u2014 Erstkauf testen</span><span class=\"wf-off\">KRITISCH</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--red);\">\u25cf Onboarding-PDF Agent bauen</span><span class=\"wf-off\">~2h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--red);\">\u25cf DSGVO-Checkbox live schalten</span><span class=\"wf-off\">~1h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--red);\">\u25cf Abo-K\u00fcndigung Workflow</span><span class=\"wf-off\">~1h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--gold);\">\u25cf M4 Zielkunden Apollo.io</span><span class=\"wf-off\">~1h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--gold);\">\u25cf M5 Kaltakquise-Agent</span><span class=\"wf-off\">~1 Tag</span></div>\n              </div>\n            </div>\n          </div>\n        </div>\n\n        <!-- \u2500\u2500 AGENTEN \u2500\u2500 -->\n        <div class=\"tp\" id=\"tab-agents\">\n          <div class=\"mets\">\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Gesamt</div><div class=\"mc-v\">24</div><div class=\"mc-s\">5 Serien</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Online</div><div class=\"mc-v gr\">24</div><div class=\"mc-s up\">Alle aktiv</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">A-Serie Finanzen</div><div class=\"mc-v\">8</div><div class=\"mc-s\">A1\u2013A8</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Chaining</div><div class=\"mc-v g\">BEREIT</div><div class=\"mc-s\">Grundger\u00fcst geplant</div></div>\n          </div>\n          <div class=\"pn\">\n            <div class=\"pnh\"><div class=\"pnt\">\u25c8 Alle 24 Agenten \u2014 Live Status</div><div class=\"pnb\">A/B/C/D/E SERIE</div></div>\n            <div class=\"pnbody\"><div class=\"ag-grid\" id=\"ag-grid\"></div></div>\n          </div>\n        </div>\n\n        <!-- \u2500\u2500 FINANZEN \u2500\u2500 -->\n        <div class=\"tp\" id=\"tab-finanzen\">\n          <div class=\"mets\">\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">MRR</div><div class=\"mc-v g\" id=\"f-mrr\">\u2014</div><div class=\"mc-s\">Monatlich</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">ARR</div><div class=\"mc-v\" id=\"f-arr\">\u2014</div><div class=\"mc-s\">Jahresbasis</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Marge</div><div class=\"mc-v gr\">92%</div><div class=\"mc-s\">Software-Basis</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Bis Million\u00e4r</div><div class=\"mc-v g\" id=\"f-mil\">\u2014</div><div class=\"mc-s\">Kunden fehlen noch</div></div>\n          </div>\n          <div class=\"two-c\">\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 Umsatz pro Kunde</div><div class=\"pnb\">STRIPE LIVE</div></div>\n              <div class=\"pnbody\" id=\"f-pay-body\"><div class=\"loading\">\u25b8 Lade...</div></div>\n            </div>\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 Meilensteine</div><div class=\"pnb\">ROADMAP</div></div>\n              <div class=\"pnbody\">\n                <div class=\"wfi\"><span class=\"wfn\">Erster zahlender Kunde</span><span class=\"wf-on\">AKTIV</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">5 Kunden \u2192 1.495 \u20ac/Mo.</span><span class=\"wf-off\">BALD</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">16 Kunden \u2192 Million\u00e4r/Jahr</span><span class=\"wf-off\">ZIEL</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">GmbH-Gr\u00fcndung</span><span class=\"wf-off\">GEPLANT</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">Holding-Struktur</span><span class=\"wf-off\">GEPLANT</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">Erste Akquisition</span><span class=\"wf-off\">2027</span></div>\n              </div>\n            </div>\n          </div>\n          <div class=\"pn\">\n            <div class=\"pnh\"><div class=\"pnt\">\u25c8 Wachstums-Prognose</div><div class=\"pnb\">WENN SO WEITER</div></div>\n            <div class=\"pnbody\"><div class=\"fc-grid\" id=\"fc-grid2\"><div class=\"loading\">\u25b8 Berechne...</div></div></div>\n          </div>\n        </div>\n\n        <!-- \u2500\u2500 SYSTEME \u2500\u2500 -->\n        <div class=\"tp\" id=\"tab-systeme\">\n          <div class=\"mets\">\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">System Health</div><div class=\"mc-v gr\">98.7%</div><div class=\"mc-s up\">Optimal</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">n8n Workflows</div><div class=\"mc-v\">3</div><div class=\"mc-s up\">Aktiv</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Stripe</div><div class=\"mc-v gr\">LIVE</div><div class=\"mc-s\">Webhook aktiv</div></div>\n            <div class=\"mc\"><div class=\"co ctl\"></div><div class=\"co cbr\"></div><div class=\"mc-l\">Supabase</div><div class=\"mc-v gr\">ONLINE</div><div class=\"mc-s\">Pro Plan aktiv</div></div>\n          </div>\n          <div class=\"three-c\">\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 n8n Workflows</div><div class=\"pnb\">STATUS</div></div>\n              <div class=\"pnbody\">\n                <div class=\"wfi\"><span class=\"wfn\">Stripe \u2192 Lexoffice \u2192 Supabase</span><span class=\"wf-on\">AKTIV</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">Upgrade-Flow Woche 10\u201313</span><span class=\"wf-on\">AKTIV</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">Willkommensmail (Gmail)</span><span class=\"wf-on\">AKTIV</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">Abo-K\u00fcndigung Flow</span><span class=\"wf-off\">OFFEN</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">Onboarding-PDF Agent</span><span class=\"wf-off\">OFFEN</span></div>\n                <div class=\"wfi\"><span class=\"wfn\">M5 Kaltakquise-Agent</span><span class=\"wf-off\">GEPLANT</span></div>\n              </div>\n            </div>\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 Infrastruktur</div><div class=\"pnb\">LIVE</div></div>\n              <div class=\"pnbody\">\n                <div class=\"syi\"><span class=\"syn\">Vercel (argonaut-os.com)</span><span class=\"sy-ok\">ONLINE</span></div>\n                <div class=\"syi\"><span class=\"syn\">Supabase Pro</span><span class=\"sy-ok\">ONLINE</span></div>\n                <div class=\"syi\"><span class=\"syn\">n8n (Hostinger VPS)</span><span class=\"sy-ok\">ONLINE</span></div>\n                <div class=\"syi\"><span class=\"syn\">Stripe Live</span><span class=\"sy-ok\">AKTIV</span></div>\n                <div class=\"syi\"><span class=\"syn\">Lexoffice</span><span class=\"sy-ok\">VERBUNDEN</span></div>\n                <div class=\"syi\"><span class=\"syn\">HubSpot Starter</span><span class=\"sy-ok\">VERBUNDEN</span></div>\n                <div class=\"syi\"><span class=\"syn\">Google Workspace</span><span class=\"sy-ok\">AKTIV</span></div>\n              </div>\n            </div>\n            <div class=\"pn\">\n              <div class=\"pnh\"><div class=\"pnt\">\u25c8 Offene Tasks</div><div class=\"pnb\">PRIORIT\u00c4T</div></div>\n              <div class=\"pnbody\">\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--red);\">\u25cf Abo-K\u00fcndigung Workflow</span><span class=\"wf-off\">~1h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--red);\">\u25cf DSGVO-Checkbox</span><span class=\"wf-off\">~1h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--red);\">\u25cf Onboarding-PDF Agent</span><span class=\"wf-off\">~2h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--gold);\">\u25cf Dashboard Popup Woche 12</span><span class=\"wf-off\">~1h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--gold);\">\u25cf Agenten im Dashboard</span><span class=\"wf-off\">~2h</span></div>\n                <div class=\"wfi\"><span class=\"wfn\" style=\"color:var(--gold);\">\u25cf Apollo Zielkunden</span><span class=\"wf-off\">~1h</span></div>\n              </div>\n            </div>\n          </div>\n        </div>\n\n        <!-- \u2500\u2500 LOGS \u2500\u2500 -->\n        <div class=\"tp\" id=\"tab-logs\">\n          <div class=\"pn\">\n            <div class=\"pnh\"><div class=\"pnt\">\u25c8 Activity Log</div><div class=\"pnb\" id=\"log-cnt\">LADE...</div></div>\n            <div class=\"pnbody\" id=\"log-body\"><div class=\"loading\">\u25b8 Lade Events...</div></div>\n          </div>\n        </div>\n\n        <div class=\"tp\" id=\"tab-imperium\">\n          <div style=\"display:flex;justify-content:space-between;align-items:flex-start;gap:12px;margin-bottom:14px;flex-wrap:wrap;\">\n            <div class=\"mc\" style=\"flex:1;min-width:200px;\">\n              <div style=\"font-size:.62rem;letter-spacing:1.5px;color:#5a7186;\">MRR \u2014 UMSATZ PRO MONAT</div>\n              <div id=\"imp-mrr\" style=\"font-size:1.7rem;font-weight:700;color:#C9A84C;font-family:'Share Tech Mono',monospace;\">0 \u20ac</div>\n              <div id=\"imp-mrr-s\" style=\"font-size:.62rem;color:#5a7186;\">0 Kunden aktiv</div>\n            </div>\n            <div class=\"mc\" style=\"flex:1;min-width:200px;text-align:right;\">\n              <div style=\"font-size:.62rem;letter-spacing:1.5px;color:#5a7186;\">ARR \u2014 UMSATZ PRO JAHR</div>\n              <div id=\"imp-arr\" style=\"font-size:1.7rem;font-weight:700;color:#00e5ff;font-family:'Share Tech Mono',monospace;\">0 \u20ac</div>\n              <div style=\"font-size:.62rem;color:#5a7186;\">Hochrechnung \u00d7 12</div>\n            </div>\n          </div>\n          <div style=\"display:flex;gap:8px;margin-bottom:10px;align-items:center;flex-wrap:wrap;justify-content:center;\">\n            <button id=\"imp-btn-akq\" class=\"imp-tabbtn\" style=\"background:#0a2740;color:#00e5ff;border:1px solid #00e5ff;border-radius:6px;padding:6px 16px;font-size:.7rem;letter-spacing:1px;cursor:pointer;font-family:'Orbitron',sans-serif;\">AKQUISITION</button>\n            <button id=\"imp-btn-imp\" class=\"imp-tabbtn\" style=\"background:transparent;color:#7a93a8;border:1px solid #1f3a52;border-radius:6px;padding:6px 16px;font-size:.7rem;letter-spacing:1px;cursor:pointer;font-family:'Orbitron',sans-serif;\">IMPERIUM</button>\n            <span id=\"imp-next\" style=\"font-size:.68rem;color:#C9A84C;margin-left:8px;\">N\u00e4chstes Ziel: \u2014</span>\n          </div>\n          <div class=\"pn\" style=\"padding:0;background:var(--navy);\">\n            <svg id=\"imp-net\" width=\"100%\" viewBox=\"0 0 680 620\" preserveAspectRatio=\"xMidYMid meet\" style=\"display:block;max-height:calc(100vh - 230px);margin:0 auto;\">\n              <text x=\"340\" y=\"300\" text-anchor=\"middle\" fill=\"#5a7186\" font-size=\"13\">Lade Imperium-Netz...</text>\n            </svg>\n          </div>\n          <div style=\"display:flex;gap:18px;justify-content:center;margin-top:8px;font-size:.62rem;flex-wrap:wrap;\">\n            <span style=\"color:#52708a;\"><span style=\"display:inline-block;width:9px;height:9px;border-radius:50%;background:#0a2030;border:1px solid #2a4a63;vertical-align:middle;\"></span> Gesperrt</span>\n            <span style=\"color:#C9A84C;\"><span style=\"display:inline-block;width:9px;height:9px;border-radius:50%;background:#C9A84C;vertical-align:middle;\"></span> Leistbar \u2014 klick = gegr\u00fcndet best\u00e4tigen</span>\n            <span style=\"color:#ffe9a8;\"><span style=\"display:inline-block;width:11px;height:11px;border-radius:50%;background:#C9A84C;border:2px solid #ffe9a8;vertical-align:middle;\"></span> Gegr\u00fcndet (Troph\u00e4e)</span>\n          </div>\n        </div>\n      </div><!-- /panel-wrap -->\n    </div><!-- /main -->\n  </div><!-- /body -->\n\n  <div class=\"footer\">\n    <div class=\"ft\">ARGONAUT OS \u2014 <span>B\u00d6BLINGEN NODE</span> \u2014 MARTIN GASPAR</div>\n    <div class=\"ft\" id=\"last-ref\">UPDATE: \u2014</div>\n    <div class=\"ft\">\u00a9 2026 <span>ARGONAUT</span></div>\n  </div>\n\n</div><!-- /app -->\n\n<script>\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// KONFIGURATION\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nconst AGENTS=[\n  {id:'A1',n:'Buchhalter',s:'A'},{id:'A2',n:'Controller',s:'A'},{id:'A3',n:'W\u00e4chter',s:'A'},{id:'A4',n:'Analyst',s:'A'},\n  {id:'A5',n:'Treasurer',s:'A'},{id:'A6',n:'Revisor',s:'A'},{id:'A7',n:'Auditor',s:'A'},{id:'A8',n:'Producer',s:'A'},\n  {id:'B1',n:'Marketer',s:'B'},{id:'B2',n:'SEO',s:'B'},{id:'B3',n:'Social',s:'B'},{id:'B4',n:'Content',s:'B'},{id:'B5',n:'Brand',s:'B'},{id:'B6',n:'Ads',s:'B'},\n  {id:'C1',n:'Ops',s:'C'},{id:'C2',n:'Supply',s:'C'},{id:'C3',n:'Quality',s:'C'},{id:'C4',n:'Legal',s:'C'},{id:'C5',n:'CRM',s:'C'},\n  {id:'D1',n:'Recruiter',s:'D'},{id:'D2',n:'HR',s:'D'},\n  {id:'E1',n:'Strategy',s:'E'},{id:'E2',n:'Intel',s:'E'},{id:'E3',n:'Research',s:'E'},\n];\nconst PR={'SOLO':29900,'SOLO BETA':29900,'SOLO_BETA':29900,'START':150000,'PRO':250000,'BUSINESS':450000,'BUS':450000,'ENTERPRISE':750000,'ENT':750000};\n\nfunction pcls(p){if(!p)return'';const u=p.toUpperCase();if(u.includes('SOLO'))return'pk-s';if(u.includes('START'))return'pk-st';if(u.includes('PRO'))return'pk-p';if(u.includes('BUS'))return'pk-b';if(u.includes('ENT'))return'pk-e';return'pk-st';}\nfunction fd(iso){if(!iso)return'\u2014';return new Date(iso).toLocaleDateString('de-DE',{day:'2-digit',month:'2-digit',year:'2-digit'});}\nfunction fe(c,d=0){return new Intl.NumberFormat('de-DE',{style:'currency',currency:'EUR',maximumFractionDigits:d}).format(c/100);}\nfunction fek(c){const v=c/100;return v>=1000?'\u20ac'+Math.round(v/1000)+'k':'\u20ac'+Math.round(v);}\n\n// Clock\nfunction tick(){document.getElementById('clock').textContent=new Date().toLocaleTimeString('de-DE',{hour:'2-digit',minute:'2-digit',second:'2-digit'});}\n\n// Tabs\nfunction showTab(id,btn){\n  if(id==='imperium'){setTimeout(loadImperium,50);}\n  document.querySelectorAll('.tp').forEach(p=>p.classList.remove('active'));\n  document.querySelectorAll('.tab').forEach(b=>b.classList.remove('active'));\n  document.querySelectorAll('.ni').forEach(n=>n.classList.remove('active'));\n  const panel=document.getElementById('tab-'+id);\n  if(panel)panel.classList.add('active');\n  if(btn)btn.classList.add('active');\n}\n\n// Agents\nfunction renderAgents(){\n  document.getElementById('ag-grid').innerHTML=AGENTS.map(a=>`\n    <div class=\"ag-card\"><div class=\"ag-dot a-on\"></div><div style=\"display:flex;flex-direction:column;gap:1px;\"><div class=\"a-id\">${a.id}</div><div class=\"a-nm\">${a.n}</div></div><div class=\"a-sr\">${a.s}</div></div>`).join('');\n}\n\n// \u2550\u2550 RADAR CANVAS \u2550\u2550\nlet radarAngle=0, radarData=[];\nfunction initRadar(){\n  const canvas=document.getElementById('radarCanvas');\n  const ctx=canvas.getContext('2d');\n  const cx=130,cy=130;\n\n  // Agent positions around outer ring\n  radarData=AGENTS.map((a,i)=>{\n    const angle=(i/AGENTS.length)*Math.PI*2-Math.PI/2;\n    return{angle,pulse:Math.random()*Math.PI*2,speed:0.8+Math.random()*0.8};\n  });\n\n  // Expanding ring pool\n  const rings=[];\n  function spawnRing(){\n    rings.push({r:18,opacity:0.9,speed:0.6+Math.random()*0.5,gold:Math.random()<0.3});\n  }\n  setInterval(spawnRing,600);\n  spawnRing();spawnRing();\n\n  function drawRadar(){\n    ctx.clearRect(0,0,260,260);\n    const t=Date.now()/1000;\n\n    // Subtle background grid rings\n    for(let r=35;r<=115;r+=25){\n      ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);\n      ctx.strokeStyle=`rgba(0,229,255,0.05)`;ctx.lineWidth=1;ctx.stroke();\n    }\n\n    // \u2500\u2500 PULSING STAR: voice-wave spiky outline \u2500\u2500\n    const numSpikes=24;\n    const baseR=80;\n    ctx.beginPath();\n    for(let i=0;i<=numSpikes*2;i++){\n      const angle=(i/numSpikes)*Math.PI-Math.PI/2;\n      // Each spike has its own wave frequency \u2192 looks like voice/sound\n      const agentIdx=i%numSpikes;\n      const agentPulse=radarData[agentIdx%radarData.length].pulse;\n      const agentSpeed=radarData[agentIdx%radarData.length].speed;\n      const wave=Math.sin(t*agentSpeed*1.8+agentPulse)*18+Math.sin(t*agentSpeed*3.1+agentPulse*1.4)*8;\n      const r= i%2===0 ? baseR+wave : baseR*0.55;\n      const x=cx+Math.cos(angle)*r;\n      const y=cy+Math.sin(angle)*r;\n      i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);\n    }\n    ctx.closePath();\n    // Gold\u2192Cyan gradient fill\n    const starGrad=ctx.createRadialGradient(cx,cy,0,cx,cy,baseR+20);\n    starGrad.addColorStop(0,'rgba(201,168,76,0.18)');\n    starGrad.addColorStop(0.5,'rgba(0,229,255,0.08)');\n    starGrad.addColorStop(1,'rgba(0,229,255,0)');\n    ctx.fillStyle=starGrad;ctx.fill();\n    // Stroke the star outline\n    const strokeGrad=ctx.createRadialGradient(cx,cy,baseR*0.4,cx,cy,baseR+20);\n    strokeGrad.addColorStop(0,'rgba(201,168,76,0.9)');\n    strokeGrad.addColorStop(0.6,'rgba(0,229,255,0.7)');\n    strokeGrad.addColorStop(1,'rgba(0,229,255,0.1)');\n    ctx.strokeStyle=strokeGrad;ctx.lineWidth=1.5;ctx.stroke();\n\n    // \u2500\u2500 EXPANDING RINGS (pulse outward like heartbeat) \u2500\u2500\n    for(let i=rings.length-1;i>=0;i--){\n      const ring=rings[i];\n      ring.r+=ring.speed;\n      ring.opacity-=0.012;\n      if(ring.opacity<=0){rings.splice(i,1);continue;}\n      ctx.beginPath();ctx.arc(cx,cy,ring.r,0,Math.PI*2);\n      const col=ring.gold?`rgba(201,168,76,${ring.opacity*0.7})`:`rgba(0,229,255,${ring.opacity*0.5})`;\n      ctx.strokeStyle=col;ctx.lineWidth=ring.gold?1.5:1;ctx.stroke();\n    }\n\n    // \u2500\u2500 AGENT DOTS on star tips \u2500\u2500\n    for(let i=0;i<numSpikes;i++){\n      const angle=(i/numSpikes)*Math.PI*2-Math.PI/2;\n      const agentPulse=radarData[i%radarData.length].pulse;\n      const agentSpeed=radarData[i%radarData.length].speed;\n      const wave=Math.sin(t*agentSpeed*1.8+agentPulse)*18+Math.sin(t*agentSpeed*3.1+agentPulse*1.4)*8;\n      const r=baseR+wave;\n      const x=cx+Math.cos(angle)*r;\n      const y=cy+Math.sin(angle)*r;\n      const brightness=0.5+Math.sin(t*agentSpeed+agentPulse)*0.5;\n      // Glow\n      const grd=ctx.createRadialGradient(x,y,0,x,y,7);\n      grd.addColorStop(0,`rgba(0,229,255,${brightness*0.8})`);\n      grd.addColorStop(1,'rgba(0,229,255,0)');\n      ctx.beginPath();ctx.arc(x,y,7,0,Math.PI*2);ctx.fillStyle=grd;ctx.fill();\n      // Dot\n      ctx.beginPath();ctx.arc(x,y,2.5,0,Math.PI*2);\n      ctx.fillStyle=`rgba(0,229,255,${brightness})`;ctx.fill();\n    }\n\n    // \u2500\u2500 CENTER GOLD GLOW \u2500\u2500\n    const cg=ctx.createRadialGradient(cx,cy,0,cx,cy,40);\n    cg.addColorStop(0,'rgba(201,168,76,0.25)');\n    cg.addColorStop(0.5,'rgba(201,168,76,0.08)');\n    cg.addColorStop(1,'rgba(201,168,76,0)');\n    ctx.beginPath();ctx.arc(cx,cy,40,0,Math.PI*2);ctx.fillStyle=cg;ctx.fill();\n\n    requestAnimationFrame(drawRadar);\n  }\n  drawRadar();\n}\n\n// Chat\nconst chatHistory=[{role:'assistant',text:'Guten Morgen, Martin! Dein Command Center ist online. Alle 24 Agenten aktiv. Wie kann ich dir heute helfen?'}];\nfunction sendChat(){\n  const inp=document.getElementById('chat-in');\n  const txt=inp.value.trim();if(!txt)return;\n  inp.value='';\n  addMsg('user',txt);\n  // Simple response\n  setTimeout(()=>{\n    const responses=['Verstanden. Ich analysiere gerade die Daten...','Roger. Ich k\u00fcmmere mich darum.','Gute Frage! Basierend auf deinen aktuellen Metriken empfehle ich...','Die Pipeline sieht gut aus. N\u00e4chster Schritt: Holzente Sch\u00e4fer kontaktieren.'];\n    addMsg('assistant',responses[Math.floor(Math.random()*responses.length)]);\n  },800);\n}\nfunction addMsg(role,text){\n  const msgs=document.getElementById('chat-msgs');\n  const isAI=role==='assistant';\n  const div=document.createElement('div');\n  div.className=`msg${isAI?'':' user'}`;\n  div.innerHTML=`<div class=\"msg-av ${isAI?'ai':'u'}\">${isAI?'A':'MG'}</div><div class=\"msg-txt\">${text}</div>`;\n  msgs.appendChild(div);\n  msgs.scrollTop=msgs.scrollHeight;\n}\n\n// Data\nlet ALL=[], currentTF='1M';\nfunction setTF(tf,btn){document.querySelectorAll('.tfb').forEach(b=>b.classList.remove('active'));btn.classList.add('active');currentTF=tf;renderCharts(tf);}\n\nfunction renderCharts(tf){\n  const n=ALL.length,months={'1M':1,'3M':3,'6M':6,'12M':12}[tf]||1;\n  const data=[];\n  for(let i=months-1;i>=0;i--){\n    const d=new Date();d.setMonth(d.getMonth()-i);\n    const lbl=d.toLocaleDateString('de-DE',{month:'short'});\n    const w=n===0?0:Math.max(0,Math.round(n*(1-i/(months+0.5))));\n    data.push({lbl,val:w});\n  }\n  const maxV=Math.max(...data.map(d=>d.val),1);\n  document.getElementById('ch-bars').innerHTML=data.map(d=>`<div class=\"bc\"><div class=\"bl2\">${d.val}</div><div class=\"bar\" style=\"height:${Math.max(4,Math.round(d.val/maxV*85))}px;\"></div><div class=\"bl2\">${d.lbl}</div></div>`).join('');\n  let mrr=0;ALL.forEach(c=>{mrr+=PR[(c.paket||'').toUpperCase()]||0;});\n  const md=data.map(d=>({lbl:d.lbl,val:Math.round(mrr*(d.val/Math.max(n,1)))}));\n  const maxM=Math.max(...md.map(d=>d.val),1);\n  document.getElementById('mrr-bars').innerHTML=md.map(d=>`<div class=\"bc\"><div class=\"bl2\">${fek(d.val)}</div><div class=\"bar gb\" style=\"height:${Math.max(4,Math.round(d.val/maxM*85))}px;\"></div><div class=\"bl2\">${d.lbl}</div></div>`).join('');\n}\n\nfunction renderForecast(mrr,n,elId){\n  const avg=n>0?Math.round(mrr/n):150000;\n  const hs=[{l:'3 Monate',c:Math.max(n,1)+Math.round(n*.5*3)},{l:'6 Monate',c:Math.max(n,1)+Math.round(n*.5*6)},{l:'12 Monate',c:Math.max(n,1)+Math.round(n*.5*12)}];\n  const el=document.getElementById(elId);\n  if(el)el.innerHTML=hs.map(h=>`<div class=\"fc-c\"><div class=\"fc-h\">${h.l}</div><div class=\"fc-v\">${fe(h.c*avg)}</div><div class=\"fc-s\">~${h.c} Kunden \u00b7 ${fe(h.c*avg*12)} / Jahr</div></div>`).join('');\n}\n\nfunction renderFeed(data){\n  const evts=data.map(c=>({time:c.created_at,text:`Neuer Kunde: ${c.email} (${c.paket||'\u2014'})`,color:'var(--cyan)'}));\n  evts.sort((a,b)=>new Date(b.time)-new Date(a.time));\n  if(evts.length===0){\n    document.getElementById('feed-cnt').textContent='0 EVENTS';\n    document.getElementById('feed-body').innerHTML='<div style=\\\"color:var(--text-dim);font-size:.75rem;font-family:\\'Share Tech Mono\\',monospace;\\\">Noch keine Events.</div>';\n    document.getElementById('log-cnt').textContent='0 EVENTS';\n    document.getElementById('log-body').innerHTML='<div style=\\\"color:var(--text-dim);font-size:.75rem;font-family:\\'Share Tech Mono\\',monospace;\\\">Noch keine Events.</div>';\n    return;\n  }\n  document.getElementById('feed-cnt').textContent=`${evts.length} EVENTS`;\n  document.getElementById('feed-body').innerHTML=evts.map(e=>`<div class=\"li\"><div class=\"lt\">${new Date(e.time).toLocaleString('de-DE',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}</div><div class=\"ld\" style=\"background:${e.color};box-shadow:0 0 4px ${e.color};\"></div><div class=\"ltx\">${e.text}</div></div>`).join('');\n  document.getElementById('log-cnt').textContent=`${evts.length} EVENTS`;\n  document.getElementById('log-body').innerHTML=evts.map(e=>`<div class=\"li\"><div class=\"lt\">${new Date(e.time).toLocaleString('de-DE',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}</div><div class=\"ld\" style=\"background:${e.color};box-shadow:0 0 4px ${e.color};\"></div><div class=\"ltx\">${e.text}</div></div>`).join('');\n}\n\nasync function loadCustomers(){\n  try{\n    const res=await fetch('/api/admin/stats');\n    if(!res.ok)throw new Error(`API ${res.status}`);\n    const data=await res.json();\n    ALL=data;const n=data.length;\n    let mrr=0;data.forEach(c=>{mrr+=PR[(c.paket||'').toUpperCase()]||0;});\n\n    // Overview metrics\n    document.getElementById('cust-n').textContent=n;\n    document.getElementById('cust-s').textContent=`${n} in Supabase`;\n    document.getElementById('c-cnt').textContent=`${n} KUNDEN`;\n    document.getElementById('mrr').textContent=mrr?fe(mrr):'0 \u20ac';\n    document.getElementById('mrr-s').textContent=`${n} Abos aktiv`;\n    // Analytics\n    document.getElementById('a-mrr').textContent=mrr?fe(mrr):'0 \u20ac';\n    document.getElementById('a-tot').textContent=n;\n    document.getElementById('a-avg').textContent=n?fe(Math.round(mrr/n)):'0 \u20ac';\n    document.getElementById('a-arr').textContent=mrr?fe(mrr*12):'0 \u20ac';\n    // Finanzen\n    document.getElementById('f-mrr').textContent=mrr?fe(mrr):'0 \u20ac';\n    document.getElementById('f-arr').textContent=mrr?fe(mrr*12):'0 \u20ac';\n    const milTarget=16*150000; // ~16 START customers\n    const milLeft=Math.max(0,Math.ceil((milTarget-mrr)/150000));\n    document.getElementById('f-mil').textContent=`${milLeft}`;\n    // Pipeline\n    document.getElementById('p-deals').textContent='0';\n    document.getElementById('p-val').textContent='0 \u20ac';\n    document.getElementById('sb-deals').textContent='0';\n\n    if(data[0]){\n      const amt=PR[(data[0].paket||'').toUpperCase()]||0;\n      document.getElementById('last-pay').textContent=amt?fe(amt):'\u2014';\n      document.getElementById('last-pay-s').textContent=fd(data[0].created_at);\n    }\n\n    // Customer table\n    const tbody=document.getElementById('cust-tbody');\n    tbody.innerHTML=n===0\n      ?'<tr><td colspan=\"4\" style=\"color:var(--text-dim);font-size:.75rem;font-family:\\'Share Tech Mono\\',monospace;padding:.5rem 0;\">Warte auf ersten Kunden \u2014 Holzente Sch\u00e4fer! \ud83d\udd31</td></tr>'\n      :data.slice(0,6).map(c=>`<tr><td>${c.email||'\u2014'}</td><td><span class=\"pk ${pcls(c.paket)}\">${c.paket||'\u2014'}</span></td><td><span class=\"sa\">\u25cf AKTIV</span></td><td>${fd(c.created_at)}</td></tr>`).join('');\n\n    // Payments\n    const payHtml=n===0\n      ?'<div style=\"color:var(--text-dim);font-size:.75rem;font-family:\\'Share Tech Mono\\',monospace;\">Noch keine Zahlungen</div>'\n      :data.slice(0,5).map(c=>{const a=PR[(c.paket||'').toUpperCase()]||0;return`<div class=\"pi\"><div class=\"pil\"><div class=\"pin\">${c.email||'\u2014'}</div><div class=\"pid\">${fd(c.created_at)} \u00b7 ${c.paket||'\u2014'}</div></div><div class=\"pia\">${a?fe(a):'\u2014'}</div></div>`;}).join('');\n    document.getElementById('pay-body').innerHTML=payHtml;\n    document.getElementById('f-pay-body').innerHTML=payHtml;\n\n    renderCharts(currentTF);\n    renderForecast(mrr,n,'fc-grid');\n    renderForecast(mrr,n,'fc-grid2');\n    renderFeed(data);\n    document.getElementById('radar-active-count').textContent=`${Math.min(n+24,24)} ONLINE`;\n\n  }catch(e){\n    ALL=[];\n    document.getElementById('cust-n').textContent='0';\n    document.getElementById('cust-s').textContent='0 in Supabase';\n    document.getElementById('c-cnt').textContent='0 KUNDEN';\n    document.getElementById('mrr').textContent='0 \u20ac';\n    document.getElementById('mrr-s').textContent='0 Abos aktiv';\n    document.getElementById('last-pay').textContent='\u2014';\n    document.getElementById('last-pay-s').textContent='\u2014';\n    document.getElementById('a-mrr').textContent='0 \u20ac';\n    document.getElementById('a-tot').textContent='0';\n    document.getElementById('a-avg').textContent='0 \u20ac';\n    document.getElementById('a-arr').textContent='0 \u20ac';\n    document.getElementById('f-mrr').textContent='0 \u20ac';\n    document.getElementById('f-arr').textContent='0 \u20ac';\n    document.getElementById('f-mil').textContent='16';\n    document.getElementById('p-deals').textContent='0';\n    document.getElementById('p-val').textContent='0 \u20ac';\n    document.getElementById('sb-deals').textContent='0';\n    document.getElementById('cust-tbody').innerHTML='<tr><td colspan=\"4\" style=\"color:var(--text-dim);font-size:.75rem;font-family:\\'Share Tech Mono\\',monospace;padding:.5rem 0;\">Warte auf ersten Kunden</td></tr>';\n    document.getElementById('pay-body').innerHTML='<div style=\"color:var(--text-dim);font-size:.75rem;font-family:\\'Share Tech Mono\\',monospace;\">Noch keine Zahlungen</div>';\n    document.getElementById('f-pay-body').innerHTML='<div style=\"color:var(--text-dim);font-size:.75rem;font-family:\\'Share Tech Mono\\',monospace;\">Noch keine Zahlungen</div>';\n    renderCharts(currentTF);\n    renderForecast(0,0,'fc-grid');\n    renderForecast(0,0,'fc-grid2');\n    renderFeed([]);\n    document.getElementById('radar-active-count').textContent='24 ONLINE';\n  }\n}\n\nasync function loadData(){\n  document.getElementById('last-ref').textContent='UPDATE: '+new Date().toLocaleTimeString('de-DE');\n  await loadCustomers();\n}\n\n// Boot \u2192 App\nwindow.addEventListener('load',()=>{\n  tick();setInterval(tick,1000);\n  renderAgents();\n  setTimeout(()=>{\n    const boot=document.getElementById('boot'),app=document.getElementById('app');\n    boot.style.transition='opacity .8s ease';boot.style.opacity='0';\n    setTimeout(()=>{\n      boot.style.display='none';\n      app.style.display='flex';\n      initRadar();\n      loadData();\n      setInterval(loadData,5*60*1000);\n      loadImperium();\n      setInterval(loadImperium,5*60*1000);\n    },800);\n  },6800);\n});\n\n// ============ IMPERIUM NETZ ============\nvar IMP_DATA={akquisition:[],imperium:[]};\nvar IMP_LAYER='akquisition';\nvar IMP_KUNDEN=0;\nvar IMP_AVG=2274.65;\n\nasync function loadImperium(){\n  try{\n    var res=await fetch('/api/admin/stats');\n    if(!res.ok)throw new Error('API');\n    var data=await res.json();\n    var custs=data.customers||[];\n    IMP_KUNDEN=custs.filter(function(c){return c.status==='aktiv'||c.status==='active';}).length;\n    var ms=data.meilensteine||[];\n    IMP_DATA.akquisition=ms.filter(function(m){return m.layer==='akquisition';});\n    IMP_DATA.imperium=ms.filter(function(m){return m.layer==='imperium';});\n    renderImperium();\n  }catch(e){\n    IMP_KUNDEN=0;\n    renderImperium();\n  }\n}\n\nfunction impPolar(r,aDeg){var a=aDeg*Math.PI/180;return [340+r*Math.cos(a),300+r*Math.sin(a)];}\nfunction impRingR(ring){return [70,135,205,265,265,290][ring]||135;}\nfunction impFmt(n){return Math.round(n).toLocaleString('de-DE');}\n\nasync function impToggle(m){\n  var willFound = m.status!=='gegruendet';\n  if(willFound){\n    if(!confirm(m.name+' \\u2014 wirklich als GEGR\\u00dcNDET best\\u00e4tigen?'))return;\n  }\n  m.status = willFound?'gegruendet':'leistbar';\n  renderImperium();\n  try{\n    await fetch('/api/admin/stats',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({id:m.id,gegruendet:willFound})});\n  }catch(e){}\n}\n\nfunction renderImperium(){\n  var svg=document.getElementById('imp-net');\n  if(!svg)return;\n  while(svg.firstChild)svg.removeChild(svg.firstChild);\n  var SVGNS='http://www.w3.org/2000/svg';\n  var data=IMP_DATA[IMP_LAYER]||[];\n\n  data.forEach(function(m){\n    var r=impRingR(m.ring); var p=impPolar(r,m.winkel||0);\n    var unlocked=IMP_KUNDEN>=m.trigger_kunden;\n    var line=document.createElementNS(SVGNS,'line');\n    line.setAttribute('x1',340);line.setAttribute('y1',300);\n    line.setAttribute('x2',p[0]);line.setAttribute('y2',p[1]);\n    line.setAttribute('stroke',unlocked?'#C9A84C':'#16344b');\n    line.setAttribute('stroke-width',unlocked?'1.2':'0.5');\n    line.setAttribute('opacity',unlocked?'0.85':'0.5');\n    svg.appendChild(line);\n  });\n\n  data.forEach(function(m){\n    var r=impRingR(m.ring); var p=impPolar(r,m.winkel||0);\n    var unlocked=IMP_KUNDEN>=m.trigger_kunden;\n    var done=m.status==='gegruendet';\n    var g=document.createElementNS(SVGNS,'g');\n    g.style.cursor=unlocked?'pointer':'default';\n    var c=document.createElementNS(SVGNS,'circle');\n    c.setAttribute('cx',p[0]);c.setAttribute('cy',p[1]);\n    if(done){c.setAttribute('r','8');c.setAttribute('fill','#C9A84C');c.setAttribute('stroke','#ffe9a8');c.setAttribute('stroke-width','3');}\n    else if(unlocked){c.setAttribute('r','6.5');c.setAttribute('fill','#C9A84C');c.setAttribute('stroke','#ffe9a8');c.setAttribute('stroke-width','1');\n      var an=document.createElementNS(SVGNS,'animate');an.setAttribute('attributeName','opacity');an.setAttribute('values','1;0.45;1');an.setAttribute('dur','1.4s');an.setAttribute('repeatCount','indefinite');c.appendChild(an);}\n    else{c.setAttribute('r','4.5');c.setAttribute('fill','#0a2030');c.setAttribute('stroke','#2a4a63');c.setAttribute('stroke-width','1');}\n    g.appendChild(c);\n    var lx=p[0],ly=p[1],anchor='middle';\n    if(p[0]>352){anchor='start';lx=p[0]+11;}\n    else if(p[0]<328){anchor='end';lx=p[0]-11;}\n    else{ly=p[1]<300?p[1]-11:p[1]+15;}\n    var t=document.createElementNS(SVGNS,'text');\n    t.setAttribute('x',lx);t.setAttribute('y',ly+3);t.setAttribute('text-anchor',anchor);\n    t.setAttribute('font-size','11');t.setAttribute('font-family',\"'Exo 2',sans-serif\");\n    t.setAttribute('fill',done?'#ffe9a8':(unlocked?'#ffd96b':'#52708a'));\n    t.textContent=m.name;\n    g.appendChild(t);\n    if(unlocked){g.addEventListener('click',function(){impToggle(m);});}\n    svg.appendChild(g);\n  });\n\n  var pulse=document.createElementNS(SVGNS,'circle');\n  pulse.setAttribute('cx',340);pulse.setAttribute('cy',300);pulse.setAttribute('r','30');\n  pulse.setAttribute('fill','none');pulse.setAttribute('stroke','#C9A84C');pulse.setAttribute('stroke-width','1');pulse.setAttribute('opacity','0.4');\n  var pa=document.createElementNS(SVGNS,'animate');pa.setAttribute('attributeName','r');pa.setAttribute('values','28;42;28');pa.setAttribute('dur','3s');pa.setAttribute('repeatCount','indefinite');pulse.appendChild(pa);\n  svg.appendChild(pulse);\n  var core=document.createElementNS(SVGNS,'circle');\n  core.setAttribute('cx',340);core.setAttribute('cy',300);core.setAttribute('r','26');\n  core.setAttribute('fill','#0a1628');core.setAttribute('stroke','#C9A84C');core.setAttribute('stroke-width','2');\n  svg.appendChild(core);\n  var a=document.createElementNS(SVGNS,'text');\n  a.setAttribute('x',340);a.setAttribute('y',310);a.setAttribute('text-anchor','middle');\n  a.setAttribute('font-size','30');a.setAttribute('font-weight','700');a.setAttribute('fill','#C9A84C');a.setAttribute('font-family',\"'Orbitron',sans-serif\");\n  a.textContent='A';svg.appendChild(a);\n\n  var mrr=IMP_KUNDEN*IMP_AVG;\n  var em=document.getElementById('imp-mrr');if(em)em.textContent=impFmt(mrr)+' \\u20ac';\n  var ems=document.getElementById('imp-mrr-s');if(ems)ems.textContent=IMP_KUNDEN+' Kunden aktiv';\n  var ea=document.getElementById('imp-arr');if(ea)ea.textContent=impFmt(mrr*12)+' \\u20ac';\n  var next=data.filter(function(m){return m.trigger_kunden>IMP_KUNDEN;}).sort(function(x,y){return x.trigger_kunden-y.trigger_kunden;})[0];\n  var en=document.getElementById('imp-next');if(en)en.textContent=next?('N\\u00e4chstes Ziel: '+next.name+' (ab '+next.trigger_kunden.toLocaleString('de-DE')+')'):'Alle Ziele erreicht \\ud83d\\udd31';\n}\n\ndocument.addEventListener('DOMContentLoaded',function(){\n  var ba=document.getElementById('imp-btn-akq'),bi=document.getElementById('imp-btn-imp');\n  if(ba)ba.addEventListener('click',function(){IMP_LAYER='akquisition';\n    ba.style.color='#00e5ff';ba.style.borderColor='#00e5ff';ba.style.background='#0a2740';\n    bi.style.color='#7a93a8';bi.style.borderColor='#1f3a52';bi.style.background='transparent';renderImperium();});\n  if(bi)bi.addEventListener('click',function(){IMP_LAYER='imperium';\n    bi.style.color='#00e5ff';bi.style.borderColor='#00e5ff';bi.style.background='#0a2740';\n    ba.style.color='#7a93a8';ba.style.borderColor='#1f3a52';ba.style.background='transparent';renderImperium();});\n});\n\n</script>\n</body>\n</html>\n";

export default function CommandCenter() {
  return (
    <>
      <iframe
        srcDoc={COMMAND_CENTER_HTML}
        style={{ position: 'fixed', inset: 0, width: '100vw', height: '100vh', border: 'none', margin: 0, padding: 0 }}
        title="ARGONAUT Command Center"
      />
      <a
        href="/admin/tenants"
        style={{
          position: 'fixed',
          bottom: 18,
          left: '50%',
          transform: 'translateX(-50%)',
          zIndex: 99999,
          fontFamily: "'Share Tech Mono', monospace",
          fontSize: 13,
          letterSpacing: '0.14em',
          color: '#00e5ff',
          background: 'rgba(0,20,32,0.92)',
          border: '1px solid rgba(0,229,255,0.6)',
          borderRadius: 8,
          padding: '9px 20px',
          textDecoration: 'none',
          boxShadow: '0 0 18px rgba(0,229,255,0.35)',
        }}
      >
        {'▣ TENANTS & MODULE'}
      </a>
    </>
  );
}
